var parameters = new Dictionary<int, ushort>() { {100,850}, {101,1500}, {102,60}, {103,1}, {104,500} };

void BatchWrite(Dictionary<int,ushort> p) {
    foreach (var kv in p) Plc.WriteHoldingRegister(kv.Key, kv.Value);
    Print("批量写入完成");
}

void BatchVerify(Dictionary<int,ushort> p) {
    bool ok = true;
    foreach (var kv in p) {
        if (Plc.ReadHoldingRegister(kv.Key) != kv.Value) {
            Print($"地址{kv.Key}验证失败");
            ok = false;
        }
    }
    if (ok) Print("全部验证通过");
}

BatchWrite(parameters);
BatchVerify(parameters);
